module RefModule(clk, rst, load, A, B, Q);input clk, rst, load;
input [3:0] A, B;
output [3:0] Q;

reg [3:0] Q_reg;
wire [3:0] sum;

  wire _n01 = A[0] ^ B[0];
  wire _c01 = A[0] & B[0];
  wire _n02 = A[1] ^ B[1] ^ _c01;
  wire _c02 = (A[1] & B[1]) | (A[1] & _c01) | (B[1] & _c01);
  wire _n03 = A[2] ^ B[2] ^ _c02;
  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};

always @(posedge clk) begin
    if (rst) begin
        Q_reg <= 4'b0;
    end else begin
        if (load) begin
            Q_reg <= sum;
        end
    end
end

assign Q = Q_reg;

endmodule
